const cfg = $('Config').first().json;
const body = $('Webhook').first().json.body || {};
const feeds = Array.isArray(body.feeds) ? body.feeds : [];
const maxPerFeed = Number(body.maxItemsPerFeed) || cfg.maxItemsPerFeed || 15;

function stripCdata(s){ return String(s||'').replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, '$1'); }
function decodeEntities(s){
  return String(s||'')
    .replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&quot;/g,'"')
    .replace(/&#0?39;/g,"'").replace(/&apos;/g,"'").replace(/&amp;/g,'&');
}
function getTag(block, tag){
  const m = block.match(new RegExp('<' + tag + '[^>]*>([\\s\\S]*?)<\\/' + tag + '>', 'i'));
  return m ? decodeEntities(stripCdata(m[1])).replace(/\s+/g,' ').trim() : '';
}
function getLink(block){
  // RSS 2.0: <link>url</link>
  const rss = block.match(/<link>([\s\S]*?)<\/link>/i);
  if (rss && stripCdata(rss[1]).trim()) return decodeEntities(stripCdata(rss[1])).trim();
  // Atom: preferir rel="alternate"
  const alt = block.match(/<link[^>]*rel=["']alternate["'][^>]*href=["']([^"']+)["']/i);
  if (alt) return decodeEntities(alt[1]);
  const any = block.match(/<link[^>]*href=["']([^"']+)["']/i);
  if (any) return decodeEntities(any[1]);
  return '';
}
function getDoi(block){
  // cubre <dc:identifier>doi:10....</dc:identifier> y enlaces doi.org
  const m = block.match(/doi(?:\.org\/|:)\s*(10\.\d{4,9}\/[^\s"'<]+)/i);
  return m ? m[1].replace(/[.,;)]+$/, '') : null;
}
function getArxivId(link, block){
  const re = /arxiv\.org\/abs\/([a-z\-]+(?:\.[A-Z]{2})?\/\d{7}|\d{4}\.\d{4,5})(?:v\d+)?/i;
  const m = String(link||'').match(re) || String(block||'').match(re);
  return m ? m[1] : null;
}

const out = { ok: true, items: [], failed: [] };

for (const f of feeds) {
  const feedUrl = (typeof f === 'string') ? f : (f.url || '');
  const type = (f && typeof f === 'object' && f.type) ? f.type : 'rss';
  const hint = (f && typeof f === 'object') ? (f.categoryHint || f.category_hint || null) : null;
  if (!feedUrl) { out.failed.push({ feed: null, error: 'no_url' }); continue; }

  let xml = '';
  try {
    xml = await this.helpers.httpRequest({
      method: 'GET', timeout: 20000, url: feedUrl,
      headers: {
        'User-Agent': 'FeedConocimiento/1.0 (+https://juliangomez.me)',
        'Accept': 'application/rss+xml, application/atom+xml, application/xml, text/xml, */*',
      },
    });
    if (typeof xml !== 'string') xml = JSON.stringify(xml);
  } catch (e) { out.failed.push({ feed: feedUrl, error: 'fetch_failed' }); continue; }

  const blocks = xml.match(/<item[\s>][\s\S]*?<\/item>|<entry[\s>][\s\S]*?<\/entry>/gi) || [];
  if (blocks.length === 0) { out.failed.push({ feed: feedUrl, error: 'no_entries' }); continue; }

  let count = 0;
  for (const b of blocks) {
    if (count >= maxPerFeed) break;
    const link = getLink(b);
    const doi = getDoi(b);
    const arxivId = getArxivId(link, b);
    if (!link && !doi && !arxivId) continue;

    const item = { sourceType: type, feedUrl };
    if (link) item.url = link;
    if (type === 'scientific') {
      if (arxivId) item.arxivId = arxivId;
      else if (doi) item.doi = doi;
    }
    if (hint) item.category_hint = hint;
    const title = getTag(b, 'title');
    if (title) item.title = title;
    const pub = getTag(b, 'pubDate') || getTag(b, 'published') || getTag(b, 'updated') || getTag(b, 'dc:date');
    if (pub) { const d = new Date(pub); if (!isNaN(d.getTime())) item.publishedAt = d.toISOString(); }

    out.items.push(item);
    count++;
  }
}

return [{ json: out }];
